<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white">
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title">
        <em class="fas fa-money-bill-wave"></em> Total Revenue Trend
      </div>
    </div>

    <!-- <div v-if="loading" class="loading">Loading...</div> -->
    <div id="totalRevenueChart" class="chart-container"></div>

    <div class="mini-stats">
      <div class="mini-stat">
        <div class="mini-stat-value">{{$n(PeakRevenue)}}</div>
        <div class="mini-stat-label">Peak Revenue</div>
      </div>
      <div class="mini-stat">
        <div class="mini-stat-value">{{$n(AverageQuarterly)}}</div>
        <div class="mini-stat-label">Average Quarterly</div>
      </div>
    </div>
  </div>
</template>

<script>
//import { analyticsService } from '../../../../services/analyticsService';
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'TotalRevenueTrendWidget',
  data() {
    return {
      loading: false,     
      quarters: null,
      revenues: null

    };
  },
  props: {
    QuarterlyTrendAnalysisData: {
      type: Array,
      default: () => []
    },
    PeakRevenue: {
      type: Number,
      
    },
    AverageQuarterly: {
      type: Number,
     
    }
  },
  mounted() {
    //debugger
    var vm = this;
    vm.QuarterlyTrendAnalysisData;
    vm.PeakRevenue;
    vm.AverageQuarterly;
    vm.loadData();
  },
  methods: {
    async loadData() {
      ////debugger
      var vm = this;
      vm.loading = true;
      try {
        vm.quarters = vm.QuarterlyTrendAnalysisData.map(d => d.Quarter_Label);
        vm.revenues = vm.QuarterlyTrendAnalysisData.map(d => d.Total_Revenue);
        vm.drawChart();

      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {
        vm.loading = false;
      }
    },
    drawChart() {
      ////debugger
      var vm = this;
      const trace = {
        x: vm.quarters,
        y: vm.revenues,
        type: 'scatter',
        mode: 'lines+markers',
        line: { color: '#10b981', width: 3 },
        marker: { size: 6 }
      };

      const layout = {
        margin: { t: 30, b: 60, l: 50, r: 30 },
        paper_bgcolor: 'transparent',
        plot_bgcolor: 'transparent',
        height: 280
      };

      Plotly.newPlot('totalRevenueChart', [trace], layout, { responsive: true });
    }
  }
};
</script>

