<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white mt-2 mb-4">
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title justify-content-between">
        <span><em class="fas fa-money-bill-trend-up"></em> Revenue Analytics (2017-2026)</span>
        <small class="text-muted text-center">Quarterly revenue trends, client metrics, and invoice analysis</small>
      </div>
      <!-- <div style="font-size: 14px; color: #7f8c8d; margin-top: 5px;">
        Quarterly revenue trends, client metrics, and invoice analysis
      </div> -->
    </div>

    <div class="p-3 w-100">
    <!-- Revenue Chart Controls -->
    <div class="revenue-controls">
      <button v-for="btn in chartButtons" :key="btn.type" class="revenue-btn"
        :class="{ active: revenueChartType === btn.type }" @click="drawRevenueChart(btn.type)">
        {{ btn.label }}
      </button>
    </div>

    <div id="revenueChart" class="chart-container"></div>
    <div v-if="stats" class="revenue-stats">
      <div class="revenue-stat-box">
        <div class="revenue-stat-value">{{ formatCurrency(stats.currentQuarterRevenue) }}</div>
        <div class="revenue-stat-label">Current Quarter Revenue (2026 Q1)</div>
      </div>
      <div class="revenue-stat-box">
        <div class="revenue-stat-value">{{ formatCurrency(stats.avgInvoiceValue) }}</div>
        <div class="revenue-stat-label">Average Invoice Value (2026 Q1)</div>
      </div>
      <div class="revenue-stat-box">
        <div class="revenue-stat-value">{{ $n(stats.activeClients) }}</div>
        <div class="revenue-stat-label">Active Clients (2026 Q1)</div>
      </div>
      <div class="revenue-stat-box">
        <div class="revenue-stat-value">{{ stats.revenueGrowth }}</div>
        <div class="revenue-stat-label">Quarter-over-Quarter Growth</div>
      </div>
    </div>
  </div>
  
  </div>
</template>

<script>
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'RevenueAnalytics',
  data() {
    return {
      revenueChartType: 'Total_Revenue',
      chartButtons: [
        { type: 'Total_Revenue', label: 'Total Revenue' },
        { type: 'Average_Invoice_Value', label: 'Average Invoice Value' },
        { type: 'Active_Clients', label: 'Active Clients' },
        { type: 'Number_of_Invoices', label: 'Number of Invoices' }
      ],
      stats: {
        currentQuarterRevenue: 13320000.00,
        avgInvoiceValue: 26586.83,
        activeClients: 246,
        revenueGrowth: '+5.3%'
      },
    };
  },
  props: {
    GetQuarterlyBillingStatsData: {
      type: String,
      required: false,
      default: () => []
    }
  },
  mounted() {
    var vm = this;
    vm.loadData();
  },
  methods: {
    formatCurrency(num) {
      if (num >= 1000000000) return '$' + (num / 1000000000).toFixed(2) + 'B';
      if (num >= 1000000) return '$' + (num / 1000000).toFixed(1) + 'M';
      if (num >= 1000) return '$' + (num / 1000).toFixed(1) + 'K';
      return '$' + num.toFixed(2);
    },
    loadData() {
      var vm = this;
      vm.drawRevenueChart('Total_Revenue');
    },
    drawRevenueChart(type = 'Total_Revenue') {
      var vm = this;
      if (!Plotly) {
        console.error('Plotly is not loaded');
        return;
      }
      
      vm.revenueChartType = type;
      
      if (!vm.GetQuarterlyBillingStatsData) {
        console.error('GetQuarterlyBillingStatsData is not available');
        return;
      }
      
      const rawResponse = vm.GetQuarterlyBillingStatsData;
      const level1 = JSON.parse(rawResponse);
      const level2 = JSON.parse(level1[0]);
      const performanceObj = level2.find(item => item.key === "quarterlyData");
      
      if (!performanceObj || !performanceObj.value) {
        console.error('quarterlyData not found in response');
        return;
      }
      
      vm.revenueData = JSON.parse(performanceObj.value);
      
      if (!vm.revenueData || !Array.isArray(vm.revenueData) || vm.revenueData.length === 0) {
        console.error('revenueData is empty or invalid');
        return;
      }

      const quarters = vm.revenueData.map(d => d.Quarter_Period || d.quarter_period || `${d.Year}-Q${d.Quarter}`);
      const values = vm.revenueData.map(d => d[type] || 0);

      let title, yAxisTitle, hovertemplate, tickformat

      switch (type) {
        case 'Total_Revenue':
          title = 'Total Revenue Over Time (2017-2026)'
          yAxisTitle = 'Revenue ($)'
          hovertemplate = '<b>%{x}</b><br>Revenue: $%{y:,.2f}<extra></extra>'
          tickformat = '$,.0f'
          break
        case 'Average_Invoice_Value':
          title = 'Average Invoice Value Over Time (2017-2026)'
          yAxisTitle = 'Average Invoice Value ($)'
          hovertemplate = '<b>%{x}</b><br>Avg Invoice: $%{y:,.2f}<extra></extra>'
          tickformat = '$,.0f'
          break
        case 'Active_Clients':
          title = 'Active Clients Over Time (2017-2026)'
          yAxisTitle = 'Number of Active Clients'
          hovertemplate = '<b>%{x}</b><br>Active Clients: %{y:,}<extra></extra>'
          tickformat = ','
          break
        case 'Number_of_Invoices':
          title = 'Number of Invoices Over Time (2017-2026)'
          yAxisTitle = 'Number of Invoices'
          hovertemplate = '<b>%{x}</b><br>Invoices: %{y:,}<extra></extra>'
          tickformat = ','
          break
      }

      const mainTrace = {
        x: quarters,
        y: values,
        mode: 'lines+markers',
        name: title.split(' ')[0] + ' ' + title.split(' ')[1],
        line: {
          color: '#3b82f6',
          width: 3,
          shape: 'spline'
        },
        marker: {
          size: 6,
          color: '#3b82f6'
        },
        hovertemplate: hovertemplate
      }

      let traces = [mainTrace]
      let annotations = []

      if (type === 'Total_Revenue') {
        const filteredData = vm.revenueData.filter(d => d.Year > 2017 || (d.Year === 2017 && d.Quarter > 1));
        const filteredQuarters = filteredData.map(d => d.Quarter_Period);
        const filteredValues = filteredData.map(d => d[type]);
        const xValues = filteredData.map((_, i) => i)

        const n = xValues.length
        const sumX = xValues.reduce((a, b) => a + b, 0)
        const sumY = filteredValues.reduce((a, b) => a + b, 0)
        const sumXY = xValues.reduce((sum, x, i) => sum + x * filteredValues[i], 0)
        const sumXX = xValues.reduce((sum, x) => sum + x * x, 0)

        const slope = (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX)
        const intercept = (sumY - slope * sumX) / n

        const trendY = xValues.map(x => slope * x + intercept)

        const trendTrace = {
          x: filteredQuarters,
          y: trendY,
          mode: 'lines',
          name: 'Revenue Trend',
          line: {
            color: 'rgba(59, 130, 246, 0.5)',
            width: 2,
            dash: 'dash'
          },
          hovertemplate: '<b>%{x}</b><br>Trend: $%{y:,.0f}<extra></extra>'
        }

        traces.push(trendTrace)

        const peakRevenue = Math.max(...values);
        const peakIndex = values.indexOf(peakRevenue);
        const peakQuarter = quarters[peakIndex];

        annotations.push({
          x: peakQuarter,
          y: peakRevenue,
          xref: 'x',
          yref: 'y',
          text: `Peak: $${vm.formatNumber(peakRevenue)}`,
          showarrow: true,
          arrowhead: 2,
          arrowsize: 1,
          arrowwidth: 2,
          arrowcolor: '#10b981',
          ax: 0,
          ay: -40,
          bgcolor: 'white',
          bordercolor: '#10b981',
          borderwidth: 1,
          borderpad: 4,
          font: {
            size: 12,
            color: '#10b981'
          }
        });
      }

      const layout = {
        title: {
          text: title,
          font: {
            size: 16,
            color: '#2c3e50'
          }
        },
        xaxis: {
          title: 'Quarter',
          tickangle: -45,
          gridcolor: '#f1f1f1',
          titlefont: { size: 14 },
          tickfont: { size: 12 }
        },
        yaxis: {
          title: yAxisTitle,
          tickformat: tickformat,
          gridcolor: '#f1f1f1',
          titlefont: { size: 14 },
          tickfont: { size: 12 }
        },
        hovermode: 'closest',
        margin: { t: 60, b: 80, l: 80, r: 30 },
        paper_bgcolor: "transparent",
        plot_bgcolor: "transparent",
        showlegend: true,
        legend: {
          orientation: 'h',
          y: -0.2,
          x: 0.5,
          xanchor: 'center'
        },
        annotations: annotations
      };

      Plotly.newPlot('revenueChart', traces, layout, { responsive: true });
    },
    formatNumber(num) {
      if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
      if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
      return num.toString();
    }
  }
};
</script>

